example.code:
{
  "name": "get_weather",
  "description": "Get current weather for a location. Call this when the user asks about weather conditions.",
  "input_schema": {
    "type": "object",
    "properties": {
      "location": {"type": "string", "description": "City name, e.g., 'Kyiv, Ukraine'"},
      "unit": {"type": "string", "enum": ["celsius", "fahrenheit"], "description": "Temperature unit"}
    },
    "required": ["location"]
  }
}
